import{_ as n,c as i,o as t,a1 as a}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Schnellstart: Antigravity Auth Installation & Konfiguration | OpenCode","description":"Lernen Sie die Installation und Konfiguration des Antigravity Auth Plugins. Schließen Sie die Google OAuth-Authentifizierung in 10 Minuten ab, senden Sie die erste Modellanfrage und verifizieren Sie den erfolgreichen Zugriff auf Claude- und Gemini-Modelle.","frontmatter":{"title":"Schnellstart: Antigravity Auth Installation & Konfiguration | OpenCode","sidebarTitle":"In 10 Minuten startklar","subtitle":"Schnellstart: Antigravity Auth Installation & Konfiguration","description":"Lernen Sie die Installation und Konfiguration des Antigravity Auth Plugins. Schließen Sie die Google OAuth-Authentifizierung in 10 Minuten ab, senden Sie die erste Modellanfrage und verifizieren Sie den erfolgreichen Zugriff auf Claude- und Gemini-Modelle.","order":1},"headers":[],"relativePath":"de/NoeFabris/opencode-antigravity-auth/start/index.md","filePath":"de/NoeFabris/opencode-antigravity-auth/start/index.md"}'),r={name:"de/NoeFabris/opencode-antigravity-auth/start/index.md"};function l(u,e,s,o,h,d){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="schnellstart" tabindex="-1">Schnellstart <a class="header-anchor" href="#schnellstart" aria-label="Permalink to &quot;Schnellstart&quot;">​</a></h1><p>Dieses Kapitel hilft Ihnen, das Antigravity Auth Plugin von Grund auf zu nutzen. Sie erfahren mehr über den Kernwert des Plugins, schließen die Installation und OAuth-Authentifizierung ab und senden eine erste Modellanfrage, um zu überprüfen, ob die Konfiguration erfolgreich ist.</p><h2 id="lernpfad" tabindex="-1">Lernpfad <a class="header-anchor" href="#lernpfad" aria-label="Permalink to &quot;Lernpfad&quot;">​</a></h2><p>Lernen Sie in der folgenden Reihenfolge, wobei jeder Schritt auf dem vorherigen aufbaut:</p><h3 id="_1-plugin-ubersicht" tabindex="-1">1. <a href="./what-is-antigravity-auth/">Plugin-Übersicht</a> <a class="header-anchor" href="#_1-plugin-ubersicht" aria-label="Permalink to &quot;1. [Plugin-Übersicht](./what-is-antigravity-auth/)&quot;">​</a></h3><p>Erfahren Sie mehr über den Kernwert, die Anwendungsszenarien und Risikohinweise des Antigravity Auth Plugins.</p><ul><li>Beurteilen Sie, ob das Plugin für Ihr Anwendungsszenario geeignet ist</li><li>Lernen Sie die unterstützten KI-Modelle kennen (Claude Opus 4.5, Sonnet 4.5, Gemini 3 Pro/Flash)</li><li>Verstehen Sie die Nutzungsrisiken und Hinweise</li></ul><h3 id="_2-schnellinstallation" tabindex="-1">2. <a href="./quick-install/">Schnellinstallation</a> <a class="header-anchor" href="#_2-schnellinstallation" aria-label="Permalink to &quot;2. [Schnellinstallation](./quick-install/)&quot;">​</a></h3><p>Schließen Sie die Plugin-Installation und erste Authentifizierung in 5 Minuten ab.</p><ul><li>Zwei Installationsmethoden (KI-gestützt / Manuelle Konfiguration)</li><li>Modelldefinitionen konfigurieren</li><li>Google OAuth-Authentifizierung durchführen</li></ul><h3 id="_3-oauth-2-0-pkce-authentifizierung" tabindex="-1">3. <a href="./first-auth-login/">OAuth 2.0 PKCE-Authentifizierung</a> <a class="header-anchor" href="#_3-oauth-2-0-pkce-authentifizierung" aria-label="Permalink to &quot;3. [OAuth 2.0 PKCE-Authentifizierung](./first-auth-login/)&quot;">​</a></h3><p>Verstehen Sie den OAuth 2.0 PKCE-Authentifizierungsablauf und schließen Sie die erste Anmeldung ab.</p><ul><li>Verstehen Sie den Sicherheitsmechanismus der PKCE-Authentifizierung</li><li>Schließen Sie die erste Anmeldung ab, um API-Zugriff zu erhalten</li><li>Erfahren Sie mehr über die automatisierte Token-Aktualisierung</li></ul><h3 id="_4-erste-anfrage" tabindex="-1">4. <a href="./first-request/">Erste Anfrage</a> <a class="header-anchor" href="#_4-erste-anfrage" aria-label="Permalink to &quot;4. [Erste Anfrage](./first-request/)&quot;">​</a></h3><p>Senden Sie eine erste Modellanfrage und überprüfen Sie, ob die Installation erfolgreich war.</p><ul><li>Senden Sie Ihre erste Antigravity-Modellanfrage</li><li>Verstehen Sie die <code>--model</code>- und <code>--variant</code>-Parameter</li><li>Beheben Sie häufige Modellanfragefehler</li></ul><h2 id="voraussetzungen" tabindex="-1">Voraussetzungen <a class="header-anchor" href="#voraussetzungen" aria-label="Permalink to &quot;Voraussetzungen&quot;">​</a></h2><p>Bevor Sie mit diesem Kapitel beginnen, stellen Sie bitte sicher:</p><ul><li>✅ OpenCode CLI ist installiert (Befehl <code>opencode</code> verfügbar)</li><li>✅ Ein verwendbares Google-Konto ist vorhanden (für OAuth-Authentifizierung)</li></ul><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Nach Abschluss des Schnellstarts können Sie:</p><ul><li><strong><a href="./../platforms/available-models/">Verfügbare Modelle kennenlernen</a></strong> — Entdecken Sie alle unterstützten Modelle und deren Variantenkonfigurationen</li><li><strong><a href="./../advanced/multi-account-setup/">Mehrere Konten konfigurieren</a></strong> — Richten Sie mehrere Google-Konten ein, um Kontingente zu bündeln</li><li><strong><a href="./../faq/common-auth-issues/">Häufige Authentifizierungsprobleme</a></strong> — Konsultieren Sie die Fehlerbehebungsanleitung bei Problemen</li></ul>',22)])])}const c=n(r,[["render",l]]);export{g as __pageData,c as default};
